<script lang="ts">import {onMount} from 'svelte';import AppShell from '$lib/components/AppShell.svelte';import PageHeader from '$lib/components/PageHeader.svelte';import AdminStatCard from '$lib/components/AdminStatCard.svelte';import AdminSection from '$lib/components/AdminSection.svelte';import StatusBadge from '$lib/components/StatusBadge.svelte';import {currentUser} from '$lib/stores/user';import {fetchAdminOverview, type AdminOverview} from '$lib/api';import { getErrorMessage } from '$lib/errors';let data:AdminOverview|null=null;let loading=false;let error='';const load=async()=>{loading=true;error='';try{data=await fetchAdminOverview();}catch(error:unknown){error=getErrorMessage(error,'Erreur');}finally{loading=false;}};onMount(load);</script>
