<AdminSection title="Alertes"><div class="g"><AdminStatCard label="Rules enabled" value={String(data?.alerts?.rules_enabled??0)}/><AdminStatCard label="Sent 24h" value={String(data?.alerts?.deliveries_sent_24h??0)}/><AdminStatCard label="Failed 24h" value={String(data?.alerts?.deliveries_failed_24h??0)}/><AdminStatCard label="Skipped 24h" value={String(data?.alerts?.deliveries_skipped_24h??0)}/></div></AdminSection>
